+fn make_proof_lineage(cap_proofs: &[&str], flow_proofs: &[&str]) -> FusionProofLineage {
+    FusionProofLineage::new(
+        cap_proofs.iter().map(|s| s.to_string()).collect(),
+        flow_proofs.iter().map(|s| s.to_string()).collect(),
+        epoch(1),
+    )
+}
